class Solution {
 private static final long MOD = 1000000007L;
 public int minAbsoluteSumDiff(int[] nums1, int[] nums2) {
 int n = nums1.length;
 long[] diff = new long[n];
 long org = 0L;
 long res = 0L;
 int[] list = new int[n];

 for (int i = 0; i < n; i++) {
 diff[i] = Math.abs(nums1[i] - nums2[i]);
 res += diff[i];
 list[i] = nums1[i];
 }

 org = res;
 Arrays.sort(list);

 for (int i = 0; i < n; i++) {
 long tmp = org - diff[i];

 int ind = Arrays.binarySearch(list, nums2[i]);

 if (ind >= 0) {
 res = Math.min(res, tmp);
 } else {
 ind = - (ind + 1);

 if (ind == n) {
 tmp += (long) Math.abs(nums2[i] - list[n-1]);
 } else {
 if (ind > 0) {
 long del = Math.min(Math.abs(nums2[i] - list[ind]), Math.abs(nums2[i] - list[ind-1]));
 tmp += del;
 } else {
 long del = Math.abs(nums2[i] - list[ind]);
 tmp += del;
 }
 }

 res = Math.min(res, tmp);
 }
 }

 return (int)(res % MOD);
 }
}

