class Solution {
    public long minimumFuelCost(int[][] roads, int seats) {
        Map<Integer, List<Integer>> graph = new HashMap<>();
        for (int[] road : roads) {
            graph.putIfAbsent(road[0], new ArrayList<>());
            graph.get(road[0]).add(road[1]);
            graph.putIfAbsent(road[1], new ArrayList<>());
            graph.get(road[1]).add(road[0]);
        }

        //System.out.println(graph);

        Set<Integer> set = new HashSet<>();
        //ans[0] is number of people in this node
        //ans[1] is the fuel used till this node
        long[] ans = helper(0, graph, seats, set);

        return ans[1];
    }

    long[] helper(int node, Map<Integer, List<Integer>> graph, int seats, Set<Integer> set) {
        long[] tmp = new long[]{1, 0};
        set.add(node);
        if (graph.containsKey(node)) {
            for (int neighbor : graph.get(node)) {
                if (set.contains(neighbor)) {
                    continue;
                }
                long[] next = helper(neighbor, graph, seats, set);
                tmp[0] += next[0];
                tmp[1] += next[1] + (next[0] / seats) + ((next[0] % seats) == 0 ? 0 : 1);
            }
        }

        return tmp;
    }
}

