    ll maxBalancedSubsequenceSum(vector<int>& nums) {  // !
        ll largest = *max_element(all(nums));
        if (largest <= 0) {
            return largest;
        }

        ll n = nums.size();

        SLL S;
        rep(i, 0, n) {
            if (nums[i] <= 0) {
                nums[i] = 0;
            }
        }


        // seems like dp... like you insert items into a bag
        VLL B(n);
        rep(i, 0, n) {
            B[i] = nums[i] - i;
            S.insert(B[i]);
        }

        MLL M;
        ll index = 0;
        for (auto x : S) {
            M[x] = index++;
        }
        ll m = M.size();
        SegTree::build(0, m - 1, 1);

        VLL dp(n, -1);
        ll ans = -inf;
        rep(i, 0, n) {
            // as you go across
            ll b = B[i];

            ll q = -inf;
            SegTree::query(0, M[b], 1, q);
            ll cur = nums[i] + max(q, 0LL);

            dp[i] = cur;
            SegTree::update(M[b], M[b], 1, cur);
            upmax(ans, cur);
        }
        // debug(dp);
        return ans;
    }
