public class Solution {
    public String addBoldTag(String s, String[] dict) {
        int n = s.length();
        if (n == 0) {
            return "";
        }

        int[] dp = new int[1 + n];
        Arrays.fill(dp, -1);
        dp[0] = 0;
        for (int i = 0; i < n; i++) {
            String sub = s.substring(i);
            for (String str : dict) {
                if (sub.startsWith(str)) {
                    int len = str.length();
                    dp[i + len] = Math.max(dp[i + len], len);
                }
            }
        }

        List<String> arr = new ArrayList<>();
        List<Boolean> comb = new ArrayList<>();
        int i = n;
        while (i > 0) {
            if (dp[i] == -1) {
                arr.add(s.charAt(i - 1) + "");
                comb.add(false);
                i--;
            }
            else {
                int j = i;
                int left = i - dp[i];
                StringBuilder sb = new StringBuilder();
                while (j > left) {
                    sb.append(s.charAt(j - 1));
                    j--;
                    if (dp[j] != -1) {
                        left = Math.min(left, j - dp[j]);
                    }
                }
                arr.add(sb.reverse().toString());
                comb.add(true);
                i = j;
            }
        }

        Collections.reverse(arr);
        Collections.reverse(comb);
        StringBuilder res = new StringBuilder();
        for (i = 0; i < arr.size(); i++) {
            if (comb.get(i)) {
                res.append("<b>");
                res.append(arr.get(i));
                res.append("</b>");
            }
            else {
                res.append(arr.get(i));
            }
        }

        return res.toString();
    }
}

