 static long gcd(long a, long b) {
 if (a < b) {
 return gcd(b, a);
 }
 while (b > 0) {
 long tmp = b;
 b = a % b;
 a = tmp;
 }
 return a;
 }

 static long inverse(long a, long m) {
 long[] ans = extgcd(a, m);
 return ans[0] == 1 ? (ans[1] + m) % m : -1;
 }

 private static long[] extgcd(long a, long m) {
 if (m == 0) {
 return new long[]{a, 1, 0};
 } else {
 long[] ans = extgcd(m, a % m);
 long tmp = ans[1];
 ans[1] = ans[2];
 ans[2] = tmp;
 ans[2] -= ans[1] * (a / m);
 return ans;
 }
 }

 private static List<Integer> primes(double upperBound) {
 var limit = (int) Math.sqrt(upperBound);
 var isComposite = new boolean[limit + 1];
 var primes = new ArrayList<Integer>();
 for (int i = 2; i <= limit; i++) {
 if (isComposite[i]) {
 continue;
 }
 primes.add(i);
 int j = i + i;
 while (j <= limit) {
 isComposite[j] = true;
 j += i;
 }
 }
 return primes;
 }

}

