	def ShortestDistance(self, matrix):
		(m, n) = (len(matrix), len(matrix[0]))
		valid = lambda x, y: (x, y) == (n - 1, m - 1) or (0 <= x < n and 0 <= y < m and (matrix[y][x] != 0))
		ans = [[0] * m for _ in range(n)]

		def walk(x, y):
			if not valid(x, y):
				return False
			ans[y][x] = 1
			if (x, y) == (n - 1, m - 1):
				return True
			for step in range(1, matrix[y][x] + 1):
				if walk(x + step, y):
					return True
				if walk(x, y + step):
					return True
			ans[y][x] = 0
			return False
		return ans if walk(0, 0) else [[-1]]

