 Q = [i for i in range(N, 0, -1)]
 if P != sorted(P):
 for i in range(N):
 if K > 0:
 if Q[i] != P[i]:
 j = P.index(max(P[i + 1:]))
 (P[i], P[j]) = (P[j], P[i])
 K -= 1
 else:
 break
 return P

