class Solution {
 public:
 bool strongPasswordCheckerII(const string &password) {
 const int n = ISIZE(password);
 // It has at least 8 characters.
 if (n < 8) return false;

 // It contains at least one lowercase letter.
 bool ok = false;
 for (auto c : password) {
 if ('a' <= c && c <= 'z') {
 ok = true;
 break;
 }
 }
 if (!ok) return false;

 // It contains at least one uppercase letter.
 ok = false;
 for (auto c : password) {
 if ('A' <= c && c <= 'Z') {
 ok = true;
 break;
 }
 }
 if (!ok) return false;
 // dump(1);

 // It contains at least one digit.
 ok = false;
 for (auto c : password) {
 if ('0' <= c && c <= '9') {
 ok = true;
 break;
 }
 }
 if (!ok) return false;

 // It contains at least one special character. The special characters are the characters in the following
 // string: "!@#$%^&*()-+".
 string special = "!@#$%^&*()-+";
 set<char> st;
 for (char sp : special) {
 st.insert(sp);
 }
 ok = false;
 for (auto c : password) {
 if (st.count(c) > 0) {
 ok = true;
 break;
 }
 }
 if (!ok) return false;

 // It does not contain 2 of the same character in adjacent positions (i.e., "aab"
 // violates this condition, but "aba" does not).
 TREP(int, i, 1, n) {
 if (password[i - 1] == password[i]) {
 return false;
 }
 }
 return true;
 }
};

