class Solution {
    public String makeFancyString(String s) {
        List<Character> output = new ArrayList();

        Character curr = null;
        int occurrence = 0;
        for(int i=0; i<s.length(); i++) {
            char x = s.charAt(i);

            if(curr == null || curr != x) {
                curr = x;
                occurrence = 0;
            }

            if(curr == x && occurrence < 2) {
                output.add(curr);
                occurrence++;
            }
        }

        return output.stream().map(String::valueOf).collect(Collectors.joining());
    }
}

