 }
 private int dfs(int[] stones, int pos, int[] cache) {
 int len = stones.length;
 if (pos >= len) return 0;
 if (cache[pos] != Integer.MAX_VALUE) {
 return cache[pos];
 }
 int d1 = stones[pos] - dfs(stones, pos+1, cache);
 int d2 = Integer.MIN_VALUE;
 int d3 = Integer.MIN_VALUE;
 if (pos + 1 < len) {
 d2 = stones[pos] + stones[pos+1] - dfs(stones, pos+2, cache);
 }
 if (pos + 2 < len) {
 d3 = stones[pos] + stones[pos+1] + stones[pos+2] - dfs(stones, pos+3, cache);
 }
 int res = Math.max(d1, Math.max(d2, d3));
 cache[pos] = res;
 return res;
 }
}

