/**
 * Definition for a binary tree node.
 * struct TreeNode {
 * int val;
 * TreeNode *left;
 * TreeNode *right;
 * TreeNode() : val(0), left(nullptr), right(nullptr) {}
 * TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}
 * TreeNode(int x, TreeNode *left, TreeNode *right) : val(x), left(left), right(right) {}
 * };
 */
class Solution {
public:
 TreeNode* replaceValueInTree(TreeNode* root) {
 queue<pair<TreeNode*, TreeNode*>> q; //{Current Node, Parent Node}
 q.push({root, NULL});
 int depth = 0;
 while(!q.empty()){
 int sz = q.size();
 vector<pair<TreeNode*, TreeNode*>> vec;
 int sum = 0; //Total Sum for Level
 unordered_map<TreeNode*, int> mp; //Parent -> Sum of Children Values
 while(sz--){
 auto p = q.front();
 q.pop();
 sum += p.first->val;
 mp[p.second] += p.first->val;
 p.first->val = 0;
 vec.push_back(p);
 if(p.first->left) q.push({p.first->left, p.first});
 if(p.first->right) q.push({p.first->right, p.first});
 }
 if(depth >= 1){
 for(auto &p : vec){
 p.first->val = sum - mp[p.second];
 }
 }
 depth++;
 }
 return root;
 }
};

