class Solution {
 public int[][] diagonalSort(int[][] mat) {
 int m=mat.length,n=mat[0].length;
 int[][] ret=new int[m][n];

 for (int i=m-1;i>=0;--i){
 int x=i,y=0;
 ArrayList<Integer> tmp=new ArrayList<Integer>();
 while (x>=0 && x<=m-1 && y>=0 && y<=n-1){
 tmp.add(mat[x][y]);
 x++;y++;
 }
 Collections.sort(tmp);
 x=i;y=0;
 int cnt=0;
 while (x>=0 && x<=m-1 && y>=0 && y<=n-1){
 ret[x][y]=tmp.get(cnt);
 x++;y++;cnt++;
 } 
 }
 for (int i=1;i<=n-1;++i){
 int x=0,y=i;
 ArrayList<Integer> tmp=new ArrayList<Integer>();
 while (x>=0 && x<=m-1 && y>=0 && y<=n-1){
 tmp.add(mat[x][y]);
 x++;y++;
 }
 Collections.sort(tmp);
 x=0;y=i;
 int cnt=0;
 while (x>=0 && x<=m-1 && y>=0 && y<=n-1){
 ret[x][y]=tmp.get(cnt);
 x++;y++;cnt++;
 } 
 }


 return ret;
 }
}

