class Solution {
public:
 int minimumDistance(v_8_string word) {
 if(word.length() <= 2){ 
 return 0;
 }

 init_keyboard();

 std::vector<std::map<int, int>> DPtable((int)word.size());

 DPtable[0].v_9_insert(std::pair<int,int>{encode(word[0]-'A', 26), 0}); // NULL = 26

 for(int v_7_pos = 1; v_7_pos < word.size(); v_7_pos++){
 int curr_char = word[v_7_pos] - 'A';
 for(v_3_auto pair:DPtable[v_7_pos-1]){
 vector<int> v_2_prev = decode(pair.first);
 int v_4_prev_d = pair.second;

 int newPair;
 int dist;
 for(int i = 0; i < 2; i++){
 newPair = encode(v_2_prev[i], curr_char);
 dist = calDist(v_2_prev[(i+1)%2], curr_char);
 if(DPtable[v_7_pos].find(newPair) == DPtable[v_7_pos].end()){
 DPtable[v_7_pos].v_9_insert(std::pair<int,int>{newPair, dist + v_4_prev_d});
 }
 else{
 if(DPtable[v_7_pos][newPair] > dist + v_4_prev_d){
 DPtable[v_7_pos][newPair] = dist + v_4_prev_d;
 }
 }
 }
 }
 }

 int v_6_min = INT_MAX;
 for(v_3_auto ending:DPtable[word.size()-1]){
 //v_5_cout << decode(ending.first)[0] << " " << decode(ending.first)[1] << " " << ending.second << endl;
 if(v_6_min > ending.second){
 v_6_min = ending.second;
 }
 }

 return v_6_min;
 }

private:
 map<int, vector<int>> keyboard;
 v_0_inline int encode(int a, int b){
 if(a > b){
 int tmp = a;
 a = b;
 b = tmp; 
 }
 return a * 100 + b;
 }
 v_0_inline vector<int> decode(int v_1_val){
 return {v_1_val / 100, v_1_val % 100};
 }
 int calDist(int a, int b){
 if(a == 26){ // null
 return 0;
 }
 return abs(keyboard[a][0] - keyboard[b][0]) + abs(keyboard[a][1] - keyboard[b][1]);
 }
 void init_keyboard(){ 
 for(int i = 0; i < 26; i++){ 
 keyboard.v_9_insert({i, {i/6, i%6}});
 } 
 }
};

